mapper.select:
SELECT r.*,
       (
           SELECT a.id FROM application a
           WHERE a.resume_id = r.id AND a.deleted = 0

               AND a.job_id = #{jobId}


               AND a.status = #{applicationStatus}

           ORDER BY a.apply_time DESC
           LIMIT 1
       ) AS applicationId,
       (
           SELECT a.job_id FROM application a
           WHERE a.resume_id = r.id AND a.deleted = 0

               AND a.job_id = #{jobId}


               AND a.status = #{applicationStatus}

           ORDER BY a.apply_time DESC
           LIMIT 1
       ) AS jobId,
       (
           SELECT j.title FROM application a
           LEFT JOIN job_post j ON a.job_id = j.id AND j.deleted = 0
           WHERE a.resume_id = r.id AND a.deleted = 0

               AND a.job_id = #{jobId}


               AND a.status = #{applicationStatus}

           ORDER BY a.apply_time DESC
           LIMIT 1
       ) AS jobTitle,
       (
           SELECT a.status FROM application a
           WHERE a.resume_id = r.id AND a.deleted = 0

               AND a.job_id = #{jobId}


               AND a.status = #{applicationStatus}

           ORDER BY a.apply_time DESC
           LIMIT 1
       ) AS applicationStatus
FROM resume r


        AND r.upload_by = #{uploadBy}


        AND r.parse_status = #{parseStatus}


        AND r.original_filename LIKE CONCAT('%', #{keyword}, '%')


        AND r.tags LIKE CONCAT('%', #{tag}, '%')


        AND EXISTS (
            SELECT 1 FROM application a2 
            WHERE a2.resume_id = r.id AND a2.job_id = #{jobId} AND a2.deleted = 0
        )


        AND EXISTS (
            SELECT 1 FROM application a3 
            WHERE a3.resume_id = r.id AND a3.status = #{applicationStatus} AND a3.deleted = 0
        )


ORDER BY r.upload_time DESC
